// Socket.IO v4 minimal client (WebSocket only)
var io = function(url) {
  var s = {
    _cbs: {},
    _connected: false,
    _url: url || location.origin,
    _sid: null
  };

  Object.defineProperty(s, 'connected', {
    get: function() { return s._connected; }
  });

  s.on = function(e, cb) {
    if (!s._cbs[e]) s._cbs[e] = [];
    s._cbs[e].push(cb);
    return s;
  };

  s.emit = function(e, data) {
    if (!s._ws || s._ws.readyState !== 1) return;
    s._ws.send('42' + JSON.stringify([e, data]));
  };

  s.disconnect = function() {
    if (s._ws) s._ws.close();
  };

  s._fire = function(e, args) {
    if (s._cbs[e]) {
      s._cbs[e].forEach(function(cb) {
        try { cb.apply(null, args); } catch(ex) {}
      });
    }
  };

  s._connect = function() {
    var wsUrl = s._url.replace(/^http/, 'ws').replace(/\/$/, '') +
                '/socket.io/?EIO=4&transport=websocket';
    try {
      s._ws = new WebSocket(wsUrl);
    } catch(e) {
      setTimeout(s._connect, 3000);
      return;
    }

    s._ws.onopen = function() {};

    s._ws.onmessage = function(ev) {
      var d = ev.data;
      // Ping -> Pong
      if (d === '2') { s._ws.send('3'); return; }
      // Open packet
      if (d.charAt(0) === '0') {
        try { s._sid = JSON.parse(d.slice(1)).sid; } catch(e) {}
        // Send connect to default namespace
        s._ws.send('40');
      }
      // Connect ack
      if (d.startsWith('40')) {
        s._connected = true;
        s._fire('connect', []);
      }
      // Event
      if (d.startsWith('42')) {
        try {
          var arr = JSON.parse(d.slice(2));
          s._fire(arr[0], [arr[1]]);
        } catch(e) {}
      }
      // Disconnect
      if (d.startsWith('41')) {
        s._connected = false;
        s._fire('disconnect', []);
      }
    };

    s._ws.onclose = function() {
      s._connected = false;
      s._fire('disconnect', []);
      setTimeout(s._connect, 3000);
    };

    s._ws.onerror = function() {};
  };

  s._connect();
  return s;
};
